INSERT INTO project
	(admin_id, title, summary, team_size, key_features, tech_stack
	,start_date, end_date, github_url, demo_url, ppt_url, is_published) 
VALUES
	(1, #{title}, #{summary}, #{teamSize}, #{keyFeatures}, #{techStack}
	,#{startDate}, #{endDate}, #{githubUrl}, #{demoUrl}, #{pptUrl}, #{isPublished});

mapper.update:
UPDATE project
SET
	title = #{title}
	,summary = #{summary}
	,team_size = #{teamSize}
	,key_features = #{keyFeatures}
	,tech_stack = #{techStack}
	,start_date = #{startDate}
	,end_date = #{endDate}
	,github_url = #{githubUrl}
	,demo_url = #{demoUrl}
	,ppt_url = #{pptUrl}
	,is_published = #{isPublished}
WHERE
	id = #{id}
	AND admin_id = 1

UPDATE project_note
SET title = #{title}, url = #{url}
WHERE
	project_id = #{projectId}
	AND id = #{id}

UPDATE section
SET title = #{title}, content = #{content}



			project_id = #{projectId}


			about_id = #{aboutId}



	AND id = #{id}

UPDATE image
SET ori_name = #{oriName}, saved_name = #{savedName}, extension = #{extension}
WHERE
	project_id = #{projectId}
	AND about_id = #{aboutId}
	AND id = #{id}

